// nav-guard.js
// Purpose: if the main site's index.html nav is ever regenerated by another
// process and one of the "extra module" links below is dropped, this script
// re-inserts it on page load. This file lives in breath-sounds/ and is not
// touched by the main site's health-content publishing process.
//
// Currently guards:
//   #nav-breath  (呼吸音教學 → breath-sounds/index.html)
//   #nav-ekg     (心電圖教學 → ekg/index.html)
// To add another guarded module later, copy one of the two blocks in
// ensureExtraNav() and adjust the id / href / label.
(function () {
  function ensureExtraNav() {
    var healthLink = document.getElementById('nav-health');
    // Fallback anchor if nav-health itself is ever missing/renamed.
    var fallbackNav = document.querySelector('.main-nav') || document.querySelector('.nav-r') || document.querySelector('nav');

    function insertAfter(referenceEl, newEl) {
      if (referenceEl && referenceEl.parentNode) {
        referenceEl.insertAdjacentElement('afterend', newEl);
      } else if (fallbackNav) {
        fallbackNav.appendChild(newEl);
      }
    }

    // ── 呼吸音教學 ──
    if (!document.getElementById('nav-breath')) {
      var breathLink = document.createElement('a');
      breathLink.href = 'breath-sounds/index.html';
      breathLink.id = 'nav-breath';
      breathLink.textContent = String.fromCodePoint(0x1FAC1) + ' 呼吸音教學';
      // Anchor next to the health-education link, which has stayed stable
      // even when the nav container's class name changed (.main-nav -> .nav-r).
      insertAfter(healthLink, breathLink);
    }

    // ── 心電圖教學 ──
    if (!document.getElementById('nav-ekg')) {
      var ekgLink = document.createElement('a');
      ekgLink.href = 'ekg/index.html';
      ekgLink.id = 'nav-ekg';
      ekgLink.textContent = String.fromCodePoint(0x2764) + String.fromCodePoint(0xFE0F) + ' 心電圖教學';
      // Prefer sitting right after the (now-guaranteed-present) breath-sounds
      // link so the two teaching-module links stay grouped together.
      var breathEl = document.getElementById('nav-breath');
      insertAfter(breathEl || healthLink, ekgLink);
    }
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', ensureExtraNav);
  } else {
    ensureExtraNav();
  }
})();
